from flask import Flask, request, logging
import os

app = Flask(__name__)

# Create a logger instance
logger = logging.getLogger('authentication')
logger.setLevel(logging.INFO)

# Log all login attempts to the application log file
@app.route('/login', methods=['POST'])
def login():
    username = request.form['username']
    password = request.form['password']
    email = request.form['email']
    ip_address = request.headers.get('X-Forwarded-For') or request.remote_addr
    user_agent = request.headers.get('User-Agent')

    logger.info(f'Login attempt: {username} - {password} ({ip_address}) - {user_agent}')

# Set the path of the application log file
application_log_file = 'app.log'

# Create a rotating file handler to manage the logs
file_handler = logging.handlers.RotatingFileHandler(application_log_file, maxBytes=1024 * 1024, backupCount=5)
logger.addHandler(file_handler)